const sgMail = require('@sendgrid/mail');
const twilio = require('twilio');

const SENDGRID_API_KEY = process.env.SENDGRID_API_KEY || 'SG.azure_demo_key_123';
const TWILIO_ACCOUNT_SID = process.env.TWILIO_ACCOUNT_SID || 'AC1234567890abcdef';
const TWILIO_AUTH_TOKEN = process.env.TWILIO_AUTH_TOKEN || 'demo_auth_token';

sgMail.setApiKey(SENDGRID_API_KEY);

const allowedEmailDomains = ['example.com', 'test.com'];
const allowedPhoneNumbers = ['+1234567890'];

function validateEmail(email) {
    if (!email || typeof email !== 'string') return false;
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    const domain = email.split('@')[1];
    return emailRegex.test(email) && allowedEmailDomains.includes(domain);
}

function validatePhoneNumber(phone) {
    if (!phone || typeof phone !== 'string') return false;
    const phoneRegex = /^\+?[1-9]\d{1,14}$/;
    return phoneRegex.test(phone) && allowedPhoneNumbers.includes(phone);
}

module.exports = async function (context, req) {
    try {
        const { type, to, subject, text, html } = req.body;

        if (!type || !to) {
            context.res = {
                status: 400,
                body: { error: 'Missing required parameters: type and to' }
            };
            return;
        }

        if (type === 'email') {
            if (!validateEmail(to)) {
                context.res = {
                    status: 400,
                    body: { error: 'Invalid email address' }
                };
                return;
            }

            const msg = {
                to,
                from: 'noreply@example.com',
                subject: subject || 'Default Subject',
                text: text || '',
                html: html || ''
            };

            await sgMail.send(msg);
            context.res = {
                status: 200,
                body: { message: 'Email sent successfully' }
            };
        } else if (type === 'sms') {
            if (!validatePhoneNumber(to)) {
                context.res = {
                    status: 400,
                    body: { error: 'Invalid phone number' }
                };
                return;
            }

            const client = twilio(TWILIO_ACCOUNT_SID, TWILIO_AUTH_TOKEN);
            await client.messages.create({
                body: text || 'Default message',
                from: '+1234567890',
                to
            });

            context.res = {
                status: 200,
                body: { message: 'SMS sent successfully' }
            };
        } else {
            context.res = {
                status: 400,
                body: { error: 'Invalid type. Use "email" or "sms"' }
            };
        }
    } catch (error) {
        context.log.error('Error sending message:', error);
        context.res = {
            status: 500,
            body: { error: 'Failed to send message' }
        };
    }
};